// 初始化值
const defaultConfig = {
    线路: hosts[0],
    发现页来源: "番茄",
    发现页类型: "小说"
};

// 获取云端配置
function getCloudSettings(r) {
    if (r == undefined) r = false;
    const {
        java,
        cache
    } = this;
    let c = this.getVariable('云端配置').version;
    if (r || !c) {
        java.longToast(`\n正在更新最新配置`);
        try {
            let url = `/static/source_config/config.json`;
            //	java.longToast(url)
            let js = this.request(url);
            js = JSON.parse(String(js));
            let intc = parseInt(c);
            let intv = parseInt(js['version']);
            if (intc >= intv) {
            	    java.longToast(`\n已是最新配置：${js['version']}`);
            	    return;
            	} else if (!intc && intv) {
            		java.longToast(`\n已初始化配置：${intv}`);
            		} else if (intc < intv || !intc && intv) {
            java.longToast(`\n已更新配置：${intc}→${intv}`);
            } else {
            java.longToast(`\n获取配置失败：请切换线路再试试~`);
            return;
            }
            this.setVariable('云端配置', js);

            return js;
        } catch (e) {
            java.longToast(`\n获取最新配置失败：${e}`);
        }
    }
}

// 统一获取和解析变量
function _getParsedVariable() {
    const {
        source,
        java
    } = this;
    let v = source.getVariable();
    try {
        return JSON.parse(v);
    } catch {
        return defaultConfig;
    }
}

// 获取设置变量
function getLoginInfo(k) {
    const {
        source,
        java
    } = this;
    let res = source.getLoginInfoMap();
    if (!res) {
        res = defaultConfig;
    }
    if (res[k] == '❌') {
        return '0';
    } else if (res[k] == '✅') {
        return '1';
    }
    return res[k]
}

// 还原
function deleteVariable() {
    const {
        source,
        java,
        cache
    } = this;
    source.setVariable('');
    cache.delete('gyksconfig');
    java.longToast('\n所有设置已还原到初始化导入状态');
}

// 获取源变量
function getVariable(k) {
    if (k == undefined) k = "";
    const { source } = this;
    let parsed = {}
    try {
        parsed = JSON.parse(source.getVariable());
    } catch {}
    if (k == "") {
        return parsed;
    }
    let value = parsed[k];
    if (value == undefined) {
        value = defaultConfig[k];
    }
    return value != undefined ? value : "";
}

// 设置源变量
function setVariable(k, v, t) {
    if (t == undefined) t = true;
    const {
        source,
        java
    } = this;
    const vs = this.getVariable();
    vs[k] = v;
    source.setVariable(JSON.stringify(vs, null, 4));
    if (k != '云端配置' && t) {
        java.toast(`\n设置 ${k} 为 ${v}`)
    }
}

// 获取正在使用的线路
function BaseUrl() {
    let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
    let h = this.getVariable("线路");
    if (!h || String(h) == "undefind") {
        h = hostsbk[0]
    }
    return h;
}

// 切换线路
function switchToNextLine(toast) {
    if (toast == undefined) toast = false;
    const currentLine = this.BaseUrl();
    let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
    let currentIndex = hostsbk.findIndex(item => item == currentLine);
    let nextIndex = (currentIndex + 1) % hostsbk.length;
    const nextLine = hostsbk[nextIndex];
    this.setVariable("线路", nextLine,false);
    let switchToast = this.getVariable("切换提醒") || "true";
    if (toast && switchToast  == "true") {
        this.java.longToast(`\n${toast}\n自动切换到:${nextLine}`)
    }
    return nextLine;
}


