function parseBadMap(str) {
    str = str
        .replace(/^{|}$/g, '');

    const result = {};

    str.split(',').forEach(item => {
        const parts = item.split('=');

        if (parts.length === 2) {
            const key = parts[0].trim();
            const value = parts[1].trim();

            result[key] = value;
        }
    });

    return result;
}

function findItemIndex(data, item_id) {
    if (!data || !Array.isArray(data)) {
        return 0;
    }
    for (let i = 0; i < data.length; i++) {
        if (data[i] && data[i].item_id == item_id) {
            return i;
        }
    }
    return 0;
}

// 判断当前环境
function checkEnv() {
    const {
        java,
        source
    } = this;

    try {
        java.qread();
        return "轻阅读";
    } catch (e) {}

    try {
        if (typeof java.reLoginView == 'function') {
            return "改版";
        }
        new Packages.io.legato.kazusa.utils.TimeoutCancellationException('');
        return "改版";
    } catch (e) {}
    try {
        java.deviceID();
        return "苹果";
    } catch (e) {}

    if (typeof source.loginUi == 'function') {
        return "安卓";
    }

    return "改版";
}

// 获取番茄token
function getFqToken() {
    const {
        java,
        cookie
    } = this;

    try {
        let cookieValue = String(cookie.getCookie('fanqienovel.com')) || String(java.getCookie('fanqienovel.com'));
        let parts = cookieValue.split(";");
        for (let part of parts) {
            if (part.includes("sessionid")) {
                return part.split("=")[1];
            }
        }
    } catch {}
    return "";
}

// 获取登陆token
function getToken() {
    const {
        java,
        cookie
    } = this;
    let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
    try {
        for (let h of hostsbk) {
            let cookieValue = String(cookie.getCookie(h)) || String(java.getCookie(h));
            let parts = cookieValue.split(";");
            for (let part of parts) {
                if (part.includes("qttoken")) {
                    return part.split("=")[1];
                }
            }
        }
    } catch {}
    return "";
}

// 移除ck
function removeAllCookies() {
    const {
        java,
        cookie
    } = this;
    let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
    for (let h of hostsbk) {
        cookie.removeCookie(h);
    }
    cookie.removeCookie('fanqienovel.com');
    java.toast('\n已退出登陆')
}

// 设置ck
function setAllCookies(ck) {
    const {
        cookie
    } = this;
    let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
    for (let h of hostsbk) {
        cookie.setCookie(h, ck);
    }
}

// 请求封装
function request(url, method, body, req, index) {
    if (method == undefined) method = 'GET';
    if (body == undefined) body = {};
    if (req == undefined) req = true;
    if (index == undefined) index = 0;

    let urla = url;
    if (!url.includes('http')) {
        urla = this.BaseUrl() + url;
    }

    const { java } = this;
    let device = '';
    try {
        device = java.androidId();
    } catch {
        try {
            device = java.deviceID();
        } catch {}
    }

    let qttoken = this.getToken();
    let options = {
        method: method,
        headers: {
            'cookie': `qttoken=${qttoken};deviceId=${device};`,
            'Content-Type': 'application/json'
        },
        body: JSON.stringify(body)
    };

    urla = `${urla},${JSON.stringify(options)}`;
    java.log(urla);

    if (!req) {
        return urla;
    }

    const startTime = new Date().getTime();

    let data;
    let requestTimedOut = false;
    let requestFailed = false;

    try {
        data = java.ajax(urla);
        JSON.parse(data);
    } catch (error) {
        requestFailed = true;
    } finally {
        const endTime = new Date().getTime();
        const duration = endTime - startTime;
        let timeout = this.getVariable('超时时间') || '5';
        timeout = parseInt(timeout)*1000
        if (!requestFailed && duration > timeout ) {
            requestTimedOut = true;
        }
    }
    if (requestTimedOut) {
        let timeoutSwitch = this.getVariable('超时自动切换') || 'true';
        if (timeoutSwitch!= "false") {
             java.log('检测到当前线路较慢，已切换线路');
            this.switchToNextLine('⚠️当前线路较慢');
        }
        return data;
    }
    if (requestFailed) {
        java.log('线路报错，自动切换下一个');
        let hostsbk = this.getVariable('云端配置')['hosts'] || hosts;
        let autoSwitch = this.getVariable('自动切换') || 'true';

        if (hostsbk.length > index && autoSwitch != "false") {
            this.switchToNextLine('❌线路报错');
            return this.request(url, method, body, req, index + 1);
        } else {
            return "";
        }
    }
    return data;
}

function parseJsonSafely(str, defaultValue) {
    if (defaultValue == null) defaultValue = null;
    try {
        return JSON.parse(str);
    } catch (e) {
        return defaultValue;
    }
}


//去除图片
function removeAllImgTags(htmlString) {
    const imgTagRegex = /<img\b[^>]*>|<\/img>|<img\b[^>]*\/>/gi;
    return htmlString.replace(imgTagRegex, '');
}

// 段评气泡生成
function paraForAndroid(content, sources) {
    let {
        java,
        cache,
        source
    } = this;

    const createSvg = this.createSvg.bind(this);

    return content.replace(/<p>(.*?)(?:<comment ident="([^"]*)" count="([^"]*)" \/>)?<\/p>/g,
        (match, text, url, count) => {
            if (url && count) {
                const click = 0;
                cache.putMemory(url, click);
                const encodedUrl = url;
                return `<p>${text}<img src="${createSvg(count, encodedUrl,sources)}"></p>`;
            } else {
                return `<p>${text}</p>`;
            }
        }
    );
}


