// 创建svg
function createSvg(number, encodedUrl, sources) {
    var displayText = number > 99 ? "99+" : number.toString();
    let data = this.getVariable('段评设置');
    let svgstyle = data['段评样式'] || "0";
    let color = data['段评边框颜色'] || "#A7A7A7";
    let tccolor = data['段评填充颜色'] || "transparent";
    let fontcolor = data['段评字体颜色'] || "#A7A7A7";
    let zdy = svgs[0];
    try {
        zdy = data['自定义段评样式'][svgstyle] || svgs[0];
    } catch {}
    const styleMap = {
        "0": svgs[0],
        "1": svgs[1],
        "2": svgs[2],
        "3": svgs[3],
        "4": svgs[4],
        "5": svgs[5],
    };
    let svg = styleMap[svgstyle] || zdy;
    svg = svg.replace('$color', color)
        .replace('$tccolor', tccolor)
        .replace('$fontcolor', fontcolor)
        .replace('$displayText', displayText);
    var jc = 'js';
    let islyc = this.checkEnv()
    if (islyc == "改版") {
        jc = 'click'
    }
    let style = data['气泡增大'] == "true" ? 'TEXT' : 'text';
    var encodedSvg = this.java.base64Encode(svg);
    return `data:image/svg+xml;base64,${encodedSvg},{"${jc}":"showCmt('${encodedUrl}', '${sources}' )","style":"${style}"}`;
}




// 显示弹窗
function showCmt(url, sources) {
    let {
        java,
        cache
    } = this;
    const currentTime = Date.now();
    const click = cache.getFromMemory(url);
    let islyc = this.checkEnv()
    if (click < 1 && islyc == "安卓") {
        cache.putMemory(url, click + 1);
        return;
    } else {
        if (islyc == "轻阅读") {
            java.startBrowserDp(url, sources + '段评');
        } else if (islyc == "改版") {
            let paradata = new Date().toLocaleDateString();
            let htmlContent = cache.get(paradata);
            if (!htmlContent || String(htmlContent).indexOf("评论") == -1) {
                java.longToast(`\n${paradata} 初始化段评页面,请稍等~`);
                try {
                    htmlContent = java.ajax(url);
                } catch {

                }

                cache.put(paradata, htmlContent);
                java.longToast(`\n${paradata} 初始化段评页面成功~`);
            }
            java.showBrowser(
                url,
                htmlContent,
                `window.java=java;`,
                JSON.stringify({
                    "expandedCornersRadius": 20,
                    "dismissOnTouchOutside": true,
                    "isDraggable": true,
                    "shouldDimBackground": true,
                    "backgroundDimAmount": 0.5,
                    "hardwareAccelerated": true,
                    "isNestedScrollingEnabled": true,
                    "isGestureInsetBottomIgnored": true,
                    "setFitToContents": true,
                    "isHideable": true,
                    "heightPercentage": 0.8
                })
            );
        } else {
            java.startBrowser(url, sources + '段评');
        }
    }
}

//源阅段评
function paraForiOS(html, sources) {
    const result = html.replace(
        /<p>(.*?)(?:<comment ident="([^"]*)" count="([^"]*)" \/>)?<\/p>/g,
        function(match, text, url, count) {
            if (url && count) {
                const encodedUrl = url.replace(/&/g, '&amp;');
                let displayCount = count;
                const numCount = Number(count);
                if (!isNaN(numCount) && numCount > 99) {
                    displayCount = '99';
                }
                return `<div rs-native>${text}<comment count="${displayCount}" onPress="java.showReadingBrowser('${encodedUrl}','${sources}段评')"></div>`;
            } else {
                return `<div rs-native>${text}</div>`;
            }
        }
    );
    return result.replace(/&#34;/g, '"');
}





//按钮切换时改变源变量并刷新发现
function show(m, t) {
    const {
        java,
        source
    } = this;
    let data = {};
    try {
        data = JSON.parse(source.getVariable())
    } catch {}
    data[t] = m;
    if (t == "发现页类型") {
        data["发现页来源"] = '番茄';
    }
    source.setVariable(JSON.stringify(data, null, 2));
    java.refreshExplore();
}

function createFilter(title, chars, defaultVal, paramKey, size, viewName) {
    if (viewName == undefined) viewName = "'请选择类型'";
    return {
        title: title,
        type: "select",
        chars: chars,
        default: defaultVal,
        "viewName": viewName,
        action: `show(infoMap['${title}'],'${paramKey}')`,
        style: {
            layout_flexGrow: 1,
            layout_flexBasisPercent: size
        }
    };
}

function createLoginFilter(title, chars, defaultVal, paramKey, size, viewName) {
    const {
        source,
        java
    } = this;
    if (viewName == undefined) viewName = "'请选择类型'";

    let loginMap = source.getLoginInfoMap();
    //java.longToast(loginMap);
    return {
        name: title,
        type: "select",
        chars: chars,
        default: defaultVal,
        "viewName": viewName,
        action: `show('${loginMap[title]}','${paramKey}')`,
