    const historyCount = document.getElementById('historyCount');

    const localVer = '${String(localVersion)}';
    let hosts = \`${hostsbk}\`;
    hosts = hosts.split(',');

const icons = ['box', 'satellite', 'link', 'bolt', 'globe', 'broadcast-tower'];

// 初始化serverConfig
const serverConfig = {
