      </div>
      <div class="color-picker-wrapper">
        <input type="color" id="fillColor" value="#FFFFFF" class="color-input">
        <input type="text" id="fillColorText" value="transparent" class="color-text-input">
        <button id="fillColorTransparent" class="transparent-btn">透明</button>
      </div>
    </div>

    <!-- 自定义样式管理 -->
    <div class="custom-style-section">
      <div class="setting-item">
        <div class="setting-info">
          <div class="setting-title">自定义样式管理</div>
          <div class="setting-desc">点击下方"+"添加新的自定义样式，支持自定义名称</div>
        </div>
        <button id="addCustomStyleBtn" class="add-style-btn">
          <i class="fas fa-plus"></i>
        </button>
      </div>

      <div id="customStylesContainer" class="custom-styles-container">
      </div>
    </div>

    <!-- 实时预览区域 -->
    <div class="preview-section">
      <div class="preview-title">
        <i class="fas fa-eye"></i>
        <span>实时预览</span>
      </div>
      <div id="previewContainer" class="preview-container"></div>
    </div>
  </div>

  <!-- 隐藏的设置数据 -->
  <div id="hiddenSettings" style="display: none;">
    <div id="settingsDiv">
      <span id="duanpingSwitchValue">${(data && data.段评开关) || 'true'}</span>
      <span id="bubbleLargeSwitchValue">${(data && data.气泡增大) || 'false'}</span>
      <span id="duanpingStyleValue">${(data && data.段评样式) || '0'}</span>
      <span id="borderColorValue">${(data && data.段评边框颜色) || '#A7A7A7'}</span>
      <span id="fontColorValue">${(data && data.段评字体颜色) || '#A7A7A7'}</span>
      <span id="fillColorValue">${(data && data.段评填充颜色) || 'transparent'}</span>
    </div>
    <textarea id="customStylesValue" style="display: none;">${typeof (data && data.自定义段评样式) == 'object' ? JSON.stringify(data.自定义段评样式) : ((data && data.自定义段评样式) || '{}')}</textarea>
  </div>
</div>

<script>
// SVG模板数据
const SVG_TEMPLATES = ${JSON.stringify(svgs)};
const STYLE_NAMES = ['起点样式', '番茄样式', '精致样式', '对话样式', '方框样式', '圆圈样式'];

// 当前设置
let settings = {
  '段评开关': '${(data && data.段评开关) || 'true'}',
  '气泡增大': '${(data && data.气泡增大) || 'false'}',
  '段评样式': '${typeof (data && data.自定义段评样式) == 'object' && (data && data.段评样式) ? data.段评样式 : ((data && data.段评样式) || '0')}',
  '段评边框颜色': '${(data && data.段评边框颜色) || '#A7A7A7'}',
  '段评字体颜色': '${(data && data.段评字体颜色) || '#A7A7A7'}',
  '段评填充颜色': '${(data && data.段评填充颜色) || 'transparent'}'
};

// 自定义样式对象 {"自定义样式1": "<svg>...</svg>", ...}
let customStyles = {};
function initCustomStyles() {
  try {
    let customStylesStr = document.getElementById('customStylesValue').textContent;
    if (!customStylesStr) {
      customStylesStr = '{}';
    }
    customStyles = JSON.parse(htmlUnescape(customStylesStr));
  } catch (e) {
    customStyles = {};
  }
}

// HTML转义函数
function htmlEscape(str) {
  if (!str) return str;
  return str.replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#039;');
}

// HTML反转义函数
function htmlUnescape(str) {
  if (!str) return str;
  return str.replace(/&amp;/g, '&')
            .replace(/&lt;/g, '<')
            .replace(/&gt;/g, '>')
            .replace(/&quot;/g, '"')
            .replace(/&#039;/g, "'");
}

// 更新隐藏设置
function updateHiddenSettings() {
  document.getElementById('duanpingSwitchValue').textContent = settings['段评开关'];
  document.getElementById('bubbleLargeSwitchValue').textContent = settings['气泡增大'];
  document.getElementById('duanpingStyleValue').textContent = settings['段评样式'];
  document.getElementById('borderColorValue').textContent = settings['段评边框颜色'];
  document.getElementById('fontColorValue').textContent = settings['段评字体颜色'];
  document.getElementById('fillColorValue').textContent = settings['段评填充颜色'];
  document.getElementById('customStylesValue').textContent = htmlEscape(JSON.stringify(customStyles));
}

// 获取下一个自定义样式名称
function getNextStyleName() {
  let count = 1;
  while (customStyles['自定义样式' + count]) {
    count++;
  }
  return '自定义样式' + count;
}

// 添加自定义样式
function addCustomStyle() {
  const name = getNextStyleName();
  customStyles[name] = '<svg xmlns="http://www.w3.org/2000/svg" width="100" height="90" viewBox="0 0 25 17" fill="none"><rect x="0.5" y="0.5" width="24" height="16" rx="2.5" ry="2.5" stroke="$color" style="stroke-opacity: 0.5; fill: $tccolor; fill-opacity: 0.5;"/><text x="12.5" y="12" text-anchor="middle" font-size="10" fill="$fontcolor" font-family="Arial, sans-serif">$displayText</text></svg>';
  renderCustomStyles();
  updateHiddenSettings();
  updateStyleSelector();
  renderPreview();
}

// 获取选中的样式名称
function getSelectedStyleName() {
  const styleValue = settings['段评样式'];
  // 如果是数字，返回默认样式名称
  if (!isNaN(styleValue)) {
    return STYLE_NAMES[parseInt(styleValue)] || styleValue;
  }
  // 如果是自定义样式，返回自定义名称
  return styleValue;
}

// 删除自定义样式
function deleteCustomStyle(name) {
  if (confirm('确定删除 "' + name + '" 吗？')) {
    delete customStyles[name];
    // 如果删除的是当前选中的样式，切换到默认样式
    if (settings['段评样式'] === name) {
      settings['段评样式'] = '0';
    }
    renderCustomStyles();
    updateHiddenSettings();
    updateStyleSelector();
    renderPreview();
  }
}

// 更新自定义样式
function updateCustomStyle(name, value) {
  customStyles[name] = value;
  updateHiddenSettings();
  renderPreview();
}

// 重命名自定义样式
function renameCustomStyle(oldName, newName) {
  if (!newName || newName.trim() == '') return;
  if (customStyles[newName] && newName != oldName) {
    alert('名称已存在');
    return;
  }
  customStyles[newName] = customStyles[oldName];
  delete customStyles[oldName];
  // 如果当前选中的是旧名称，更新为新名称
  if (settings['段评样式'] === oldName) {
    settings['段评样式'] = newName;
  }
  renderCustomStyles();
  updateHiddenSettings();
  updateStyleSelector();
  renderPreview();
}

// 渲染自定义样式列表
function renderCustomStyles() {
  const container = document.getElementById('customStylesContainer');
  container.innerHTML = '';

  if (Object.keys(customStyles).length === 0) {
    container.innerHTML = '<div class="empty-custom-styles">暂无自定义样式，点击上方"+"添加</div>';
    return;
  }

  Object.keys(customStyles).forEach((name, index) => {
    const styleCard = document.createElement('div');
    styleCard.className = 'custom-style-card';
    // 转义SVG代码中的特殊字符
    const escapedSvg = customStyles[name]
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#039;');

    styleCard.innerHTML = \`
      <div class="custom-style-header">
        <input type="text" class="style-name-input" value="\${name}" data-original="\${name}">
        <div class="style-actions">
          <button class="style-btn preview-btn" title="预览">
            <i class="fas fa-eye"></i>
          </button>
          <button class="style-btn delete-btn" title="删除">
            <i class="fas fa-trash"></i>
          </button>
        </div>
      </div>
      <textarea class="style-code-textarea" rows="4" placeholder="输入SVG代码...">\${escapedSvg}</textarea>
      <div class="style-preview-small">
        <div class="preview-svg-container"></div>
      </div>
    \`;

    // 绑定事件
    const nameInput = styleCard.querySelector('.style-name-input');
    const codeTextarea = styleCard.querySelector('.style-code-textarea');
    const deleteBtn = styleCard.querySelector('.delete-btn');
    const previewBtn = styleCard.querySelector('.preview-btn');

    nameInput.addEventListener('change', () => {
      const newName = nameInput.value.trim();
      const originalName = nameInput.dataset.original;
      if (newName != originalName) {
        renameCustomStyle(originalName, newName);
      }
    });

    codeTextarea.addEventListener('input', () => {
      updateCustomStyle(name, codeTextarea.value);
      // 更新小预览
      updateSmallPreview(styleCard.querySelector('.preview-svg-container'), codeTextarea.value);
    });

    deleteBtn.addEventListener('click', () => deleteCustomStyle(name));

    previewBtn.addEventListener('click', () => {
      // 设置为当前选中样式（使用自定义名称）
      settings['段评样式'] = name;
      document.getElementById('duanpingStyle').value = name;
      updateHiddenSettings();
      renderPreview();
    });

    // 初始化小预览
    updateSmallPreview(styleCard.querySelector('.preview-svg-container'), customStyles[name]);

    container.appendChild(styleCard);
  });
}

// 更新小预览
function updateSmallPreview(container, svgCode) {
  try {
    const preview = svgCode
      .split('$color').join(settings['段评边框颜色'])
      .split('$fontcolor').join(settings['段评字体颜色'])
      .split('$tccolor').join(settings['段评填充颜色'])
      .split('$displayText').join('99+');
    container.innerHTML = preview;
  } catch (e) {
    container.innerHTML = '<span style="color: #999; font-size: 12px;">解析失败</span>';
  }
}

// 渲染预览
function renderPreview() {
  const container = document.getElementById('previewContainer');
  container.innerHTML = '';

  // 添加默认样式
  SVG_TEMPLATES.forEach((svgTemplate, index) => {
    const svgContent = svgTemplate
      .split('$color').join(settings['段评边框颜色'])
      .split('$fontcolor').join(settings['段评字体颜色'])
      .split('$tccolor').join(settings['段评填充颜色'])
      .split('$displayText').join('99+');

    const item = document.createElement('div');
    item.className = \`preview-item \${settings['段评样式'] === String(index) ? 'selected' : ''}\`;
    item.innerHTML = \`
      \${svgContent}
      <div class="preview-label">\${STYLE_NAMES[index]}</div>
    \`;

    item.addEventListener('click', () => {
      settings['段评样式'] = String(index);
      document.getElementById('duanpingStyle').value = String(index);
      updateHiddenSettings();
      renderPreview();
    });

    container.appendChild(item);
  });

  // 添加自定义样式预览
  Object.keys(customStyles).forEach((name) => {
    const svgCode = customStyles[name];
    let svgContent;
    try {
      svgContent = svgCode
        .split('$color').join(settings['段评边框颜色'])
        .split('$fontcolor').join(settings['段评字体颜色'])
        .split('$tccolor').join(settings['段评填充颜色'])
        .split('$displayText').join('99+');
    } catch (e) {
      svgContent = '<svg width="60" height="54" viewBox="0 0 60 54"><text x="30" y="27" text-anchor="middle" fill="#999" font-size="10">解析失败</text></svg>';
    }

    const item = document.createElement('div');
    item.className = \`preview-item \${settings['段评样式'] === name ? 'selected' : ''}\`;
    item.innerHTML = \`
      \${svgContent}
      <div class="preview-label custom-label">\${name}</div>
    \`;

    item.addEventListener('click', () => {
      settings['段评样式'] = name;
      document.getElementById('duanpingStyle').value = name;
      updateHiddenSettings();
      renderPreview();
    });

    container.appendChild(item);
  });
}

// 初始化事件监听
function setupEventListeners() {
  // 段评开关
  document.getElementById('duanpingSwitch').addEventListener('change', (e) => {
    settings['段评开关'] = e.target.checked ? 'true' : 'false';
    updateHiddenSettings();
  });

  // 气泡增大开关
  document.getElementById('bubbleLargeSwitch').addEventListener('change', (e) => {
    settings['气泡增大'] = e.target.checked ? 'true' : 'false';
    updateHiddenSettings();
  });

  // 段评样式选择
  document.getElementById('duanpingStyle').addEventListener('change', (e) => {
    settings['段评样式'] = e.target.value;
    updateHiddenSettings();
    renderPreview();
  });

  // 边框颜色选择器
  document.getElementById('borderColor').addEventListener('input', (e) => {
    const color = e.target.value;
    settings['段评边框颜色'] = color;
    document.getElementById('borderColorText').value = color;
    updateHiddenSettings();
    renderPreview();
  });

  // 边框颜色文本输入
  document.getElementById('borderColorText').addEventListener('input', (e) => {
    const color = e.target.value;
    if (/^#[0-9A-Fa-f]{6}$/.test(color) || /^#[0-9A-Fa-f]{3}$/.test(color)) {
      settings['段评边框颜色'] = color;
      document.getElementById('borderColor').value = color;
      updateHiddenSettings();
      renderPreview();
    }
  });

  // 字体颜色选择器
  document.getElementById('fontColor').addEventListener('input', (e) => {
    const color = e.target.value;
    settings['段评字体颜色'] = color;
    document.getElementById('fontColorText').value = color;
    updateHiddenSettings();
    renderPreview();
  });

  // 字体颜色文本输入
  document.getElementById('fontColorText').addEventListener('input', (e) => {
    const color = e.target.value;
    if (/^#[0-9A-Fa-f]{6}$/.test(color) || /^#[0-9A-Fa-f]{3}$/.test(color)) {
      settings['段评字体颜色'] = color;
      document.getElementById('fontColor').value = color;
      updateHiddenSettings();
      renderPreview();
    }
  });

  // 填充颜色选择器
  document.getElementById('fillColor').addEventListener('input', (e) => {
    const color = e.target.value;
    settings['段评填充颜色'] = color;
    document.getElementById('fillColorText').value = color;
    updateHiddenSettings();
    renderPreview();
  });

  // 填充颜色文本输入
  document.getElementById('fillColorText').addEventListener('input', (e) => {
    const color = e.target.value;
    if (color.toLowerCase() == 'transparent' || /^#[0-9A-Fa-f]{6}$/.test(color) || /^#[0-9A-Fa-f]{3}$/.test(color)) {
      settings['段评填充颜色'] = color;
      if (color.toLowerCase() != 'transparent') {
        document.getElementById('fillColor').value = color;
      }
      updateHiddenSettings();
      renderPreview();
    }
  });

  // 透明按钮
  document.getElementById('fillColorTransparent').addEventListener('click', () => {
    settings['段评填充颜色'] = 'transparent';
    document.getElementById('fillColorText').value = 'transparent';
    document.getElementById('fillColor').value = '#FFFFFF';
    updateHiddenSettings();
    renderPreview();
  });

  // 添加自定义样式按钮
  document.getElementById('addCustomStyleBtn').addEventListener('click', addCustomStyle);
}

// 初始化UI
function initUI() {
  // 设置段评开关
  document.getElementById('duanpingSwitch').checked = settings['段评开关'] != 'false';

  // 设置气泡增大开关
  document.getElementById('bubbleLargeSwitch').checked = settings['气泡增大'] == 'true';

  // 设置段评样式
  document.getElementById('duanpingStyle').value = settings['段评样式'];

  // 设置边框颜色
  const borderColorValue = settings['段评边框颜色'];
  document.getElementById('borderColor').value = borderColorValue === 'transparent' ? '#A7A7A7' : borderColorValue;
  document.getElementById('borderColorText').value = borderColorValue;

  // 设置字体颜色
  const fontColorValue = settings['段评字体颜色'];
  document.getElementById('fontColor').value = fontColorValue === 'transparent' ? '#A7A7A7' : fontColorValue;
  document.getElementById('fontColorText').value = fontColorValue;

  // 设置填充颜色
  const fillColorValue = settings['段评填充颜色'];
  document.getElementById('fillColor').value = fillColorValue === 'transparent' ? '#FFFFFF' : fillColorValue;
  document.getElementById('fillColorText').value = fillColorValue;

  // 渲染自定义样式列表
  renderCustomStyles();

  // 更新段评样式选择器，添加自定义样式选项
  updateStyleSelector();
}

// 更新段评样式选择器
function updateStyleSelector() {
  const select = document.getElementById('duanpingStyle');
  const currentValue = settings['段评样式'];

  // 移除所有非默认选项
  while (select.options.length > 6) {
    select.remove(6);
  }

  // 添加自定义样式选项
  Object.keys(customStyles).forEach((name) => {
    const option = document.createElement('option');
    option.value = name;
    option.textContent = name;
    select.appendChild(option);
  });

  // 设置当前选中值
  select.value = currentValue;
}

// 页面加载完成后初始化
initCustomStyles();
initUI();
setupEventListeners();
renderPreview();
</script>
</body>
</html>
    `;
    let body;
    try {
        body = java.startBrowserAwait(`data:text/html;base64,${java.base64Encode(html)}`, '光遇段评设置', false).body();
    } catch (e) {
        if (islyc == "安卓") {
            java.longToast("\n当前软件版本过低，请更新软件，或者使用底部备用设置方案~");
        } else {
            java.longToast("\n请点击页面右上角√才能设置成功哦~");
        }
        return;
    }

    let settings = {};
    try {
        const getSpanText = (spanId) => {
            const regex = new RegExp('id="' + spanId + '"\s*>\s*([^<]*?)\s*<\/span>');
            const match = body.match(regex);
            return match ? match[1].trim() : "";
        };
        const getTextareaValue = (textareaId) => {
            const regex = new RegExp('<textarea[^>]*id="' + textareaId + '"[^>]*>([\\s\\S]*?)<\/textarea>', 'i');
            const match = body.match(regex);
            return match ? match[1].trim() : "";
        };
        const htmlDecode = (str) => {
            if (!str) return str;
            return str.replace(/&amp;/g, '&')
                .replace(/&lt;/g, '<')
                .replace(/&gt;/g, '>')
                .replace(/&quot;/g, '"')
                .replace(/&#039;/g, "'");
        };

        const customStylesValue = getTextareaValue('customStylesValue') || '{}';
        const decodedStyles = htmlDecode(customStylesValue);

        settings = {
            '段评开关': getSpanText('duanpingSwitchValue'),
            '气泡增大': getSpanText('bubbleLargeSwitchValue'),
            '段评样式': getSpanText('duanpingStyleValue') || '0',
            '段评边框颜色': getSpanText('borderColorValue') || '#A7A7A7',
            '段评字体颜色': getSpanText('fontColorValue') || '#A7A7A7',
            '段评填充颜色': getSpanText('fillColorValue') || 'transparent',
            '自定义段评样式': JSON.parse(decodedStyles),
        };
        const settingsText = Object.keys(settings).map(key => `${key}: ${settings[key]}`).join('\n');
        java.longToast("\n" + settingsText);
    } catch (e) {
        settings = {
            '段评开关': 'true',
            '气泡增大': 'false',
            '段评样式': '0',
            '段评边框颜色': '#A7A7A7',
            '段评字体颜色': '#A7A7A7',
            '段评填充颜色': 'transparent',
            '自定义段评样式': {},
        };
    }
    this.setVariable("段评设置", settings, false);
}

// 线路设置
function getServerSettings() {
    const {java} = this;
    let data = this.getVariable('线路');
