<script>
const HOSTS = ${JSON.stringify(hostsbk)};
let currentServer = '${data || hostsbk[0]}';

function renderServerList() {
  const serverList = document.getElementById('serverList');
  serverList.innerHTML = '';

  HOSTS.forEach((host, index) => {
    const card = document.createElement('div');
    card.className = 'server-card' + (currentServer === host ? ' selected' : '');
    card.dataset.host = host;
    card.dataset.index = index;

    card.innerHTML = \`
      <div class="server-icon">
        <i class="fas fa-server"></i>
      </div>
      <div class="server-info">
        <div class="server-url">\${host}</div>
        <div class="server-details" id="details-\${index}">状态: 检测中</div>
      </div>
      <span class="server-status checking" id="status-\${index}">
        <i class="fas fa-spinner fa-spin"></i>
        <span>检测中</span>
      </span>
      \${currentServer === host ? '<div class="selected-badge"><i class="fas fa-check"></i></div>' : ''}
    \`;

    card.addEventListener('click', () => {
      selectServer(host);
    });

    serverList.appendChild(card);
  });
}

function selectServer(host) {
  currentServer = host;

  document.querySelectorAll('.server-card').forEach(card => {
    card.classList.remove('selected');
    const badge = card.querySelector('.selected-badge');
    if (badge) badge.remove();
  });

  const selectedCard = document.querySelector(\`[data-host="\${host}"]\`);
  if (selectedCard) {
    selectedCard.classList.add('selected');
    const icon = selectedCard.querySelector('.server-icon');
    icon.style.background = 'linear-gradient(135deg, var(--color-primary), var(--color-primary-light))';
    icon.style.color = 'white';

    const statusEl = selectedCard.querySelector('.server-status');
    const newBadge = document.createElement('div');
    newBadge.className = 'selected-badge';
    newBadge.innerHTML = '<i class="fas fa-check"></i>';
    selectedCard.appendChild(newBadge);
  }

  document.getElementById('currentServer').textContent = host;
  document.getElementById('serverValue').textContent = host;
}

async function checkSingleServer(host, index) {
  const currentProtocol = window.location.protocol;
  const statusEl = document.getElementById(\`status-\${index}\`);
  const detailsEl = document.getElementById(\`details-\${index}\`);

  try {
    const serverProtocol = new URL(host).protocol;
    if (currentProtocol === 'https:' && serverProtocol === 'http:') {
      statusEl.className = 'server-status not-support';
      statusEl.innerHTML = '<i class="fas fa-exclamation-triangle"></i><span>不支持</span>';
      detailsEl.textContent = '浏览器安全策略限制';
      return;
    }

    const startTime = performance.now();
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);

    const response = await fetch(\`\${host}/health?t=\${Date.now()}\`, {
      signal: controller.signal,
      method: 'GET',
      mode: 'cors',
      cache: 'no-cache'
    });

    clearTimeout(timeout);
    const responseTime = Math.round(performance.now() - startTime);

    if (response.ok) {
      if (responseTime < 1000) {
        statusEl.className = 'server-status online';
        statusEl.innerHTML = \`<i class="fas fa-check-circle"></i><span>\${responseTime}ms</span>\`;
      } else if (responseTime < 2000) {
        statusEl.className = 'server-status slow';
        statusEl.innerHTML = \`<i class="fas fa-exclamation-circle"></i><span>\${responseTime}ms</span>\`;
      } else {
        statusEl.className = 'server-status slow';
        statusEl.innerHTML = '<i class="fas fa-exclamation-circle"></i><span>缓慢</span>';
      }
      detailsEl.textContent = '运行正常';
    } else {
      statusEl.className = 'server-status offline';
      statusEl.innerHTML = '<i class="fas fa-times-circle"></i><span>异常</span>';
      detailsEl.textContent = 'HTTP状态码: ' + response.status;
    }
  } catch (error) {
    statusEl.className = 'server-status offline';
    statusEl.innerHTML = '<i class="fas fa-times-circle"></i><span>离线</span>';
    detailsEl.textContent = '连接失败';
  }
}

async function checkServers() {
  HOSTS.forEach((_, index) => {
    const statusEl = document.getElementById(\`status-\${index}\`);
    const detailsEl = document.getElementById(\`details-\${index}\`);
    if (statusEl && detailsEl) {
      statusEl.className = 'server-status checking';
      statusEl.innerHTML = '<i class="fas fa-spinner fa-spin"></i><span>检测中</span>';
      detailsEl.textContent = '状态: 检测中';
    }
  });

  const promises = HOSTS.map((host, index) => checkSingleServer(host, index));
  await Promise.all(promises);

  const now = new Date();
  document.getElementById('lastCheckTime').textContent = \`最后检测: \${now.toLocaleTimeString()}\`;
}

document.getElementById('refreshBtn').addEventListener('click', checkServers);

document.addEventListener('DOMContentLoaded', () => {
  renderServerList();
  document.getElementById('currentServer').textContent = currentServer;
  checkServers();

  // 初始化自动切换开关
  const autoSwitchToggle = document.getElementById('autoSwitchToggle');
  const autoSwitchValue = document.getElementById('autoSwitchValue').textContent;
  autoSwitchToggle.checked = autoSwitchValue !== 'false';

  // 监听开关变化
  autoSwitchToggle.addEventListener('change', (e) => {
    document.getElementById('autoSwitchValue').textContent = e.target.checked ? 'true' : 'false';
  });

  // 初始化超时自动切换开关
  const timeoutSwitchToggle = document.getElementById('timeoutSwitchToggle');
  const timeoutSwitchValue = document.getElementById('timeoutSwitchValue').textContent;
  timeoutSwitchToggle.checked = timeoutSwitchValue !== 'false';

  // 监听超时自动切换开关变化
  timeoutSwitchToggle.addEventListener('change', (e) => {
    document.getElementById('timeoutSwitchValue').textContent = e.target.checked ? 'true' : 'false';
  });

  // 初始化超时时间下拉框
  const timeoutSelect = document.getElementById('timeoutSelect');
  const timeoutValue = document.getElementById('timeoutValue').textContent;
  timeoutSelect.value = timeoutValue;

  // 监听超时时间变化
  timeoutSelect.addEventListener('change', (e) => {
    document.getElementById('timeoutValue').textContent = e.target.value;
  });

  // 初始化切换提醒弹窗开关
  const notifySwitchToggle = document.getElementById('notifySwitchToggle');
  const notifySwitchValue = document.getElementById('notifySwitchValue').textContent;
  notifySwitchToggle.checked = notifySwitchValue !== 'false';

  // 监听切换提醒弹窗开关变化
  notifySwitchToggle.addEventListener('change', (e) => {
    document.getElementById('notifySwitchValue').textContent = e.target.checked ? 'true' : 'false';
  });
});
</script>
