function clearDevice() {
    const token = getToken();
    if (String(token).length < 10) {
        java.longToast('\n🤔请先登陆');
        return;
    }
    let res = request(`/clear`, "POST");
    res = JSON.parse(res);
    java.toast(res.code == 0 ? "\n\n📴设备清除成功" : res.msg)
    //Packages.java.lang.Thread.sleep(500)
    //checkStatus()
}

